"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { CheckCircle, Info, Mail, Star } from "lucide-react";
import { Controller, useForm } from "react-hook-form";
import { z } from "zod";

import { useSaveCryptoAddress } from "@/shared/api/query-hooks/use-crypto-addresses";
import { CryptoNetwork } from "@/shared/types/payment.types";
import { Button } from "@/shared/ui/shadcn/button";
import {
  Dialog,
  DialogContent,
  DialogTitle,
} from "@/shared/ui/shadcn/dialog";
import { Input } from "@/shared/ui/shadcn/input";
import { Label } from "@/shared/ui/shadcn/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui/shadcn/select";
import { Switch } from "@/shared/ui/shadcn/switch";

const BASE58_REGEX = /^[1-9A-HJ-NP-Za-km-z]+$/;
const HEX_REGEX = /^[0-9a-fA-F]+$/;

function validateTronAddress(address: string): string | true {
  if (!address.startsWith("T")) {
    return "TRON address must start with 'T'";
  }

  if (address.length !== 34) {
    return "TRON address must be exactly 34 characters long";
  }

  if (!BASE58_REGEX.test(address)) {
    return "TRON address must be base58 encoded (no 0, O, I, or l characters)";
  }

  return true;
}

function validateEvmAddress(address: string): string | true {
  if (!address.startsWith("0x")) {
    return "Address must start with '0x'";
  }

  if (address.length !== 42) {
    return "Address must be exactly 42 characters long";
  }

  if (!HEX_REGEX.test(address.slice(2))) {
    return "Address must contain only hexadecimal characters after '0x'";
  }

  return true;
}

function validateSolanaAddress(address: string): string | true {
  if (address.length < 32 || address.length > 44) {
    return "Solana address must be between 32 and 44 characters long";
  }

  if (!BASE58_REGEX.test(address)) {
    return "Solana address must be base58 encoded";
  }

  return true;
}

const networkValidators: Record<
  CryptoNetwork,
  (address: string) => string | true
> = {
  [CryptoNetwork.TRON]: validateTronAddress,
  [CryptoNetwork.ETHEREUM]: validateEvmAddress,
  [CryptoNetwork.BASE]: validateEvmAddress,
  [CryptoNetwork.POLYGON]: validateEvmAddress,
  [CryptoNetwork.SOLANA]: validateSolanaAddress,
};

const networkAddressHints: Record<CryptoNetwork, string> = {
  [CryptoNetwork.TRON]: "Address must start with 'T' and be 34 characters",
  [CryptoNetwork.ETHEREUM]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.BASE]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.POLYGON]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.SOLANA]: "Address must be 32–44 base58 characters",
};

const cryptoAddressSchema = z
  .object({
    network: z.nativeEnum(CryptoNetwork),
    address: z.string().min(1, "Address is required"),
    label: z.string().optional(),
    setAsDefault: z.boolean(),
  })
  .refine(
    (data) => {
      const validator = networkValidators[data.network];
      const result = validator(data.address);
      return result === true;
    },
    (data) => {
      const validator = networkValidators[data.network];
      const result = validator(data.address);
      return {
        message: typeof result === "string" ? result : "Invalid address",
        path: ["address"],
      };
    },
  );

type CryptoAddressForm = z.infer<typeof cryptoAddressSchema>;

interface AddCryptoAddressModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function AddCryptoAddressModal({
  isOpen,
  onClose,
}: AddCryptoAddressModalProps) {
  const addCryptoAddress = useSaveCryptoAddress();

  const {
    register,
    handleSubmit,
    control,
    reset,
    watch,
    formState: { errors },
  } = useForm<CryptoAddressForm>({
    resolver: zodResolver(cryptoAddressSchema),
    defaultValues: {
      network: CryptoNetwork.TRON,
      address: "",
      label: "",
      setAsDefault: false,
    },
  });

  const addressValue = watch("address");
  const selectedNetwork = watch("network");
  const hasValidAddress = !errors.address && addressValue.length > 0;

  async function onSubmit(data: CryptoAddressForm) {
    try {
      await addCryptoAddress.mutateAsync({
        network: data.network,
        address: data.address,
        label: data.label || "",
        setAsDefault: data.setAsDefault,
      });

      reset();
      onClose();
    } catch (error) {
      console.error("Failed to add crypto address:", error);
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[calc(100vw-2rem)] max-w-[500px] gap-0 rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] p-0 shadow-[0px_20px_28px_rgba(0,0,0,0.05)]">
        {/* Icon row */}
        <div className="flex items-start px-6 pt-6 pb-4">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-[#EDE9E3]">
            <Mail className="h-5 w-5 text-[#44403C]" />
          </div>
        </div>

        {/* Title + subtitle */}
        <div className="px-6 pb-5">
          <DialogTitle className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
            Add Crypto Wallet
          </DialogTitle>
          <p className="mt-1 font-new-sans text-[#A8A29E] text-sm leading-[150%]">
            Connect a wallet where you prefer to get payments.
          </p>
        </div>

        {/* Divider */}
        <div className="border-[#D6D3D1] border-t" />

        {/* Form */}
        <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col">
          <div className="flex flex-col gap-4 px-6 py-5">
            {/* Wallet Network */}
            <div className="flex flex-col gap-2">
              <Label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                Wallet Network
              </Label>
              <Controller
                name="network"
                control={control}
                render={({ field }) => (
                  <Select
                    value={field.value}
                    onValueChange={field.onChange}
                  >
                    <SelectTrigger className="h-12 rounded-[4px] border border-[#A8A29E] bg-[#EDE9E3] px-3 font-new-sans text-[#44403C] text-sm">
                      <SelectValue placeholder="Select network" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value={CryptoNetwork.TRON}>
                        TRON (TRC-20)
                      </SelectItem>
                      <SelectItem value={CryptoNetwork.ETHEREUM}>
                        Ethereum (ERC-20)
                      </SelectItem>
                      <SelectItem value={CryptoNetwork.BASE}>
                        Base
                      </SelectItem>
                      <SelectItem value={CryptoNetwork.SOLANA}>
                        Solana (SPL)
                      </SelectItem>
                      <SelectItem value={CryptoNetwork.POLYGON}>
                        Polygon
                      </SelectItem>
                    </SelectContent>
                  </Select>
                )}
              />
            </div>

            {/* Wallet Address */}
            <div className="flex flex-col gap-2">
              <Label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                Wallet Address
              </Label>
              <Input
                {...register("address")}
                placeholder="Enter a valid address"
                className="h-12 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                aria-invalid={!!errors.address}
              />
              {errors.address && (
                <p className="font-new-sans text-destructive text-xs">
                  {errors.address.message}
                </p>
              )}
              {!errors.address && hasValidAddress && (
                <p className="flex items-center gap-1 font-new-sans text-green-600 text-xs">
                  <CheckCircle className="h-3 w-3 shrink-0" />
                  Valid wallet address
                </p>
              )}
              {!(errors.address || hasValidAddress) && (
                <p className="flex items-center gap-1 font-new-sans text-[#A8A29E] text-xs">
                  <Info className="h-3 w-3 shrink-0" />
                  Address must have 42 characters
                </p>
              )}
            </div>

            {/* Wallet Name */}
            <div className="flex flex-col gap-2">
              <Label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                Wallet Name{" "}
                <span className="text-[#A8A29E]">(Optional)</span>
              </Label>
              <Input
                {...register("label")}
                placeholder="Enter a name that helps you remember this wallet"
                className="h-12 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
              />
            </div>

            {/* Mark as Primary Wallet toggle */}
            <Controller
              name="setAsDefault"
              control={control}
              render={({ field }) => (
                <div className="flex items-center justify-between rounded-[4px] bg-[#EDE9E3] px-4 py-3">
                  <div className="flex items-center gap-2">
                    <Star className="h-4 w-4 shrink-0 text-[#44403C]" />
                    <span className="font-medium font-new-sans text-[#44403C] text-sm">
                      Mark as Primary Wallet
                    </span>
                  </div>
                  <Switch
                    checked={field.value}
                    onCheckedChange={field.onChange}
                    className="data-[state=checked]:bg-[#001A8C]"
                  />
                </div>
              )}
            />

            {/* Confirm destination address — info block */}
            <div className="flex items-start gap-3 rounded-xl bg-[#EDE9E3] p-4">
              <Info className="mt-0.5 h-4 w-4 shrink-0 text-[#44403C]" />
              <div className="flex flex-col gap-0.5">
                <p className="font-medium font-new-sans text-[#44403C] text-sm leading-[150%]">
                  Confirm the destination address before sending tokens.
                </p>
                <p className="font-new-sans text-[#44403C] text-sm leading-[150%]">
                  Items sent to wrong address cannot be recovered.
                </p>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="flex gap-3 border-[#D6D3D1] border-t px-6 py-5">
            <button
              type="button"
              onClick={onClose}
              className="flex h-12 flex-1 items-center justify-center rounded-lg border border-[#A8A29E] bg-[#F5F3EF] font-medium font-new-sans text-[#44403C] text-base transition-opacity hover:opacity-70"
            >
              Back
            </button>
            <Button
              type="submit"
              loading={addCryptoAddress.isPending}
              disabled={addCryptoAddress.isPending}
              className="h-12 flex-1 rounded-lg bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base"
            >
              Add Wallet
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

