const BASE58_ALPHABET =
  "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz";
const BASE58_REGEX = /^[1-9A-HJ-NP-Za-km-z]+$/;
const HEX_REGEX = /^[0-9a-fA-F]+$/;

function base58Decode(input: string): Uint8Array | null {
  if (!BASE58_REGEX.test(input)) return null;

  let num = 0n;
  for (const char of input) {
    const index = BASE58_ALPHABET.indexOf(char);
    if (index === -1) return null;
    num = num * 58n + BigInt(index);
  }

  const bytes: number[] = [];
  while (num > 0n) {
    bytes.unshift(Number(num & 0xffn));
    num >>= 8n;
  }

  let leadingZeros = 0;
  for (const char of input) {
    if (char === "1") leadingZeros++;
    else break;
  }

  return new Uint8Array([...Array(leadingZeros).fill(0), ...bytes]);
}

async function sha256(data: Uint8Array): Promise<Uint8Array> {
  const hashBuffer = await crypto.subtle.digest("SHA-256", data);
  return new Uint8Array(hashBuffer);
}

async function validateTronAddress(address: string): Promise<string | true> {
  if (!address.startsWith("T")) {
    return "TRON address must start with 'T'";
  }
  if (address.length !== 34) {
    return "TRON address must be exactly 34 characters long";
  }

  const decoded = base58Decode(address);
  if (!decoded || decoded.length !== 25) {
    return "Invalid TRON address";
  }
  if (decoded[0] !== 0x41) {
    return "Invalid TRON address (wrong network byte)";
  }

  const payload = decoded.slice(0, 21);
  const checksum = decoded.slice(21);
  const hash = await sha256(await sha256(payload));

  for (let index = 0; index < 4; index++) {
    if (hash[index] !== checksum[index]) {
      return "Invalid TRON address (checksum mismatch)";
    }
  }

  return true;
}

function validateEvmAddress(address: string): string | true {
  if (!address.startsWith("0x")) {
    return "Address must start with '0x'";
  }
  if (address.length !== 42) {
    return "Address must be exactly 42 characters long";
  }
  if (!HEX_REGEX.test(address.slice(2))) {
    return "Address must only contain hex characters after '0x'";
  }
  return true;
}

function validateSolanaAddress(address: string): string | true {
  if (!BASE58_REGEX.test(address)) {
    return "Solana address contains invalid characters";
  }

  const decoded = base58Decode(address);
  if (!decoded || decoded.length !== 32) {
    return "Invalid Solana address (must decode to 32 bytes)";
  }

  return true;
}

const networkValidators: Record<
  CryptoNetwork,
  (address: string) => Promise<string | true> | string | true
> = {
  [CryptoNetwork.TRON]: validateTronAddress,
  [CryptoNetwork.ETHEREUM]: validateEvmAddress,
  [CryptoNetwork.BASE]: validateEvmAddress,
  [CryptoNetwork.POLYGON]: validateEvmAddress,
  [CryptoNetwork.SOLANA]: validateSolanaAddress,
};

const networkAddressHints: Record<CryptoNetwork, string> = {
  [CryptoNetwork.TRON]: "Address must start with 'T' and be 34 characters",
  [CryptoNetwork.ETHEREUM]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.BASE]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.POLYGON]: "Address must start with '0x' and be 42 characters",
  [CryptoNetwork.SOLANA]: "Address must be a valid base58-encoded public key",
};

