import { getErrorMessage } from "@/shared/types/api-error.types";
import type {
  CreateCryptoAddressRequest,
  DuplicateAddressError,
  InvalidAddressError,
  UpdateCryptoAddressRequest,
} from "@/shared/types/payment.types";
import { toast } from "@/shared/ui/notification";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type { AxiosError } from "axios";
import { ApiKeys } from "../query-keys";
import { cryptoAddressesService } from "../services/crypto-addresses.service";

export function useCryptoAddresses() {
  return useQuery({
    queryKey: ApiKeys.cryptoAddresses(),
    queryFn: () => cryptoAddressesService.listAddresses(),
  });
}

export function useCryptoAddress(id: string) {
  return useQuery({
    queryKey: ApiKeys.cryptoAddresses(id),
    queryFn: () => cryptoAddressesService.getAddress(id),
    enabled: !!id,
  });
}

export function useSaveCryptoAddress() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: CreateCryptoAddressRequest) =>
      cryptoAddressesService.createAddress(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.cryptoAddresses() });
      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
      toast.success("Crypto address saved successfully");
    },
    onError: (
      error: AxiosError<InvalidAddressError | DuplicateAddressError>,
    ) => {
      if (error?.response?.data?.error === "INVALID_TRON_ADDRESS") {
        toast.error(
          "Invalid TRON address format. Must start with T and be 34 characters.",
        );
      } else if (error?.response?.data?.error === "DUPLICATE_ADDRESS") {
        toast.error("This address has already been saved.");
      } else {
        toast.error("Failed to save crypto address");
      }
    },
  });
}

export function useUpdateCryptoAddress() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({
      id,
      data,
    }: {
      id: string;
      data: UpdateCryptoAddressRequest;
    }) => cryptoAddressesService.updateAddress(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.cryptoAddresses() });
      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
      toast.success("Crypto address updated");
    },
    onError: (error: unknown) => {
      toast.error(getErrorMessage(error, "Failed to update crypto address"));
    },
  });
}

export function useDeleteCryptoAddress() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => cryptoAddressesService.deleteAddress(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.cryptoAddresses() });
      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
      toast.success("Crypto address removed");
    },
    onError: (error: unknown) => {
      toast.error(getErrorMessage(error, "Failed to remove crypto address"));
    },
  });
}
